script:
(function(){
var canvas = document.getElementById('netCanvas');
function resize(){
  var rect = canvas.parentElement.getBoundingClientRect();
  canvas.width = rect.width;
  canvas.height = rect.height;
}
resize();
var ctx = canvas.getContext('2d');
var W, H;
function setDims(){ W = canvas.width; H = canvas.height; }
setDims();

var nodeCount = 42;
var nodes = [];
for (var i=0;i<nodeCount;i++){
  nodes.push({
    x: W*0.42 + Math.random()*W*0.58,
    y: Math.random()*H,
    vx: (Math.random()-0.5)*0.32,
    vy: (Math.random()-0.5)*0.32,
    r: 1.4 + Math.random()*1.6
  });
}

function step(){
  ctx.clearRect(0,0,W,H);
  for (var i=0;i<nodes.length;i++){
    var n = nodes[i];
    n.x += n.vx; n.y += n.vy;
    if (n.xW) n.vx*=-1;
    if (n.y<0||n.y>H) n.vy*=-1;
  }
  for (var i=0;i<nodes.length;i++){
    for (var j=i+1;j<nodes.length;j++){
      var a=nodes[i], b=nodes[j];
      var dx=a.x-b.x, dy=a.y-b.y;
      var dist=Math.sqrt(dx*dx+dy*dy);
      if (dist<95){
        ctx.strokeStyle = 'rgba(58,176,255,' + (0.35*(1-dist/95)) + ')';
        ctx.lineWidth = 0.6;
        ctx.beginPath();
        ctx.moveTo(a.x,a.y);
        ctx.lineTo(b.x,b.y);
        ctx.stroke();
      }
    }
  }
  for (var i=0;i<nodes.length;i++){
    var n = nodes[i];
    ctx.beginPath();
    ctx.arc(n.x,n.y,n.r,0,Math.PI*2);
    ctx.fillStyle = '#3ab0ff';
    ctx.shadowColor = '#3ab0ff';
    ctx.shadowBlur = 7;
    ctx.fill();
    ctx.shadowBlur = 0;
  }
  requestAnimationFrame(step);
}
step();

window.addEventListener('resize', function(){ resize(); setDims(); });

var col = document.getElementById('codeCol');
var lines = [];
var lineCount = 11;
var linuxSnippets = [
  'root@cybercafe:~$ ssh admin@10.0.0.1',
  'Connecting to node 0x4F2A...',
  'PING 192.168.1.1 56(84) bytes',
  '[ OK ] Started network daemon',
  'sudo systemctl status firewall',
  'drwxr-xr-x 3 root root 4096',
  'PID 8821 TTY pts/2 CPU 0.3%',
  'Mounting /dev/sda1 on /mnt',
  'kernel: eth0 link up 1Gbps',
  '> decrypting packet 0x9B1C',
  'auth: token accepted [200]',
  'proc: memory usage 62%',
  '$ nmap -sV 172.16.0.0/24',
  'Booting kernel 6.2.0-cyber'
];
function pickLine(){
  return linuxSnippets[Math.floor(Math.random()*linuxSnippets.length)];
}
for (var i=0;i 0.6;
  div.style.color = isRed ? '#b5342c' : '#e8e8e8';
  div.style.opacity = (0.4 + Math.random()*0.5).toFixed(2);
  div.style.overflow = 'hidden';
  div.style.textOverflow = 'ellipsis';
  div.style.maxWidth = '95%';
  div.textContent = pickLine();
  col.appendChild(div);
  lines.push(div);
}
setInterval(function(){
  var idx = Math.floor(Math.random()*lines.length);
  var el = lines[idx];
  var isRed = Math.random() > 0.6;
  el.style.color = isRed ? '#b5342c' : '#e8e8e8';
  el.textContent = pickLine();
}, 500);

var pct = 0;
var bar = document.getElementById('loadBar');
var pctLabel = document.getElementById('pct');
var loadTimer = setInterval(function(){
  pct += Math.random()*7;
  if (pct >= 100){ pct = 100; clearInterval(loadTimer); }
  bar.style.width = pct + '%';
  pctLabel.textContent = Math.floor(pct) + '%';
}, 220);
})();
